//! Integration tests for S3 download functionality

use templateflow::s3;
use tempfile::TempDir;

#[tokio::test]
#[ignore] // Ignore by default since it requires network access
async fn test_download_skeleton() {
    let temp_dir = TempDir::new().unwrap();
    let skeleton_path = temp_dir.path().join("templateflow-skel.zip");

    // Download the skeleton file
    let result = s3::download_file("templateflow-skel.zip", &skeleton_path, true).await;
    assert!(result.is_ok(), "Failed to download skeleton file: {:?}", result);

    // Verify the file exists and has content
    assert!(skeleton_path.exists());
    let metadata = std::fs::metadata(&skeleton_path).unwrap();
    assert!(metadata.len() > 0, "Downloaded file is empty");
}

#[tokio::test]
#[ignore] // Ignore by default since it requires network access
async fn test_download_template_metadata() {
    let temp_dir = TempDir::new().unwrap();
    let metadata_path = temp_dir.path().join("template_description.json");

    // Download a template metadata file
    let result = s3::download_file(
        "tpl-MNI152NLin2009cAsym/template_description.json",
        &metadata_path,
        false, // No progress bar for tests
    ).await;

    assert!(result.is_ok(), "Failed to download metadata file: {:?}", result);

    // Verify the file exists and has content
    assert!(metadata_path.exists());
    let metadata = std::fs::metadata(&metadata_path).unwrap();
    assert!(metadata.len() > 0, "Downloaded file is empty");

    // Verify it's valid JSON
    let content = std::fs::read_to_string(&metadata_path).unwrap();
    let json: serde_json::Value = serde_json::from_str(&content).unwrap();
    assert!(json.is_object());
}

#[tokio::test]
async fn test_download_if_missing() {
    let temp_dir = TempDir::new().unwrap();
    let file_path = temp_dir.path().join("test.txt");

    // Create a dummy file with content
    std::fs::write(&file_path, b"existing content").unwrap();

    // download_if_missing should return false without downloading
    let result = s3::download_if_missing("some/path", &file_path, false).await;
    assert!(result.is_ok());
    assert_eq!(result.unwrap(), false);

    // Verify content is unchanged
    let content = std::fs::read(&file_path).unwrap();
    assert_eq!(content, b"existing content");
}

#[tokio::test]
async fn test_download_empty_file_replacement() {
    let temp_dir = TempDir::new().unwrap();
    let file_path = temp_dir.path().join("empty.txt");

    // Create an empty file
    std::fs::write(&file_path, b"").unwrap();

    // download_if_missing should detect empty file and try to download
    // This will fail with a non-existent S3 path, but we're testing the logic
    let result = s3::download_if_missing("non/existent/path", &file_path, false).await;

    // The download will fail, but the empty file should have been removed
    assert!(result.is_err());
    assert!(!file_path.exists());
}

