use crate::error::{Result, TemplateFlowError};
use once_cell::sync::Lazy;
use std::env;
use std::path::PathBuf;
use std::time::Duration;

static DEFAULT_S3_ROOT: &str = "https://templateflow.s3.amazonaws.com";
static DEFAULT_TIMEOUT_SECS: u64 = 300; // 5 minutes

#[derive(Debug, Clone)]
pub struct Config {
    /// Local cache directory for templates
    pub home: PathBuf,

    /// S3 root URL for downloading templates
    pub s3_root: String,

    /// Whether to automatically update the skeleton index
    pub autoupdate: bool,

    /// Timeout for network operations
    pub timeout: Duration,
}

impl Config {
    /// Create a new Config with default values or from environment variables
    pub fn new() -> Result<Self> {
        let home = Self::get_home_dir()?;
        let s3_root = Self::get_s3_root();
        let autoupdate = Self::get_autoupdate();
        let timeout = Duration::from_secs(Self::get_timeout_secs());

        Ok(Config {
            home,
            s3_root,
            autoupdate,
            timeout,
        })
    }

    /// Get the home directory from environment or default
    fn get_home_dir() -> Result<PathBuf> {
        if let Ok(path) = env::var("TEMPLATEFLOW_HOME") {
            Ok(PathBuf::from(path))
        } else {
            let cache_dir = dirs::cache_dir()
                .ok_or_else(|| TemplateFlowError::ConfigError(
                    "Unable to determine cache directory".to_string()
                ))?;
            Ok(cache_dir.join("templateflow"))
        }
    }

    /// Get the S3 root URL from environment or default
    fn get_s3_root() -> String {
        env::var("TEMPLATEFLOW_S3_ROOT")
            .unwrap_or_else(|_| DEFAULT_S3_ROOT.to_string())
    }

    /// Get the autoupdate setting from environment or default
    fn get_autoupdate() -> bool {
        env::var("TEMPLATEFLOW_AUTOUPDATE")
            .map(|v| v.to_lowercase() != "false" && v != "0")
            .unwrap_or(true)
    }

    /// Get the timeout in seconds from environment or default
    fn get_timeout_secs() -> u64 {
        env::var("TEMPLATEFLOW_TIMEOUT")
            .ok()
            .and_then(|v| v.parse().ok())
            .unwrap_or(DEFAULT_TIMEOUT_SECS)
    }

    /// Ensure the home directory exists
    pub fn ensure_home_exists(&self) -> Result<()> {
        std::fs::create_dir_all(&self.home)?;
        Ok(())
    }

    /// Get the path to the skeleton index
    pub fn skeleton_path(&self) -> PathBuf {
        self.home.join("templateflow-skel.zip")
    }

    /// Get the path to a specific template's directory
    pub fn template_path(&self, template: &str) -> PathBuf {
        self.home.join(format!("tpl-{}", template))
    }
}

impl Default for Config {
    fn default() -> Self {
        Self::new().expect("Failed to create default config")
    }
}

/// Global configuration instance
pub static CONFIG: Lazy<Config> = Lazy::new(|| {
    Config::new().expect("Failed to initialize configuration")
});

